import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

export const useLogoutHandler = () => {
  const navigate = useNavigate();
  const [showLogoutModal, setShowLogoutModal] = useState(false);

  // Handle logout
  const handleLogout = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");
    setShowLogoutModal(false);
    navigate("/login", { replace: true });
  };

  // Prevent back button navigation to login page
  useEffect(() => {
    // Push a new history state to prevent going back
    window.history.pushState(null, null, window.location.pathname);

    // Listen for back button clicks
    const handlePopState = () => {
      // Show logout modal instead of going back
      setShowLogoutModal(true);
      // Push state again to stay on current page
      window.history.pushState(null, null, window.location.pathname);
    };

    window.addEventListener("popstate", handlePopState);

    return () => {
      window.removeEventListener("popstate", handlePopState);
    };
  }, []);

  return { handleLogout, showLogoutModal, setShowLogoutModal };
};
